
class HorizontalPodAutoscalerSpec {final CrossVersionObjectReference scaleTargetRef; final int minReplicas; final int maxReplicas; final List<MetricSpec>? metrics; final HPAScalingBehavior? behavior; HorizontalPodAutoscalerSpec({required this.scaleTargetRef, required this.minReplicas, required this.maxReplicas, this.metrics, this.behavior}); factory HorizontalPodAutoscalerSpec.fromJson(Map<String, dynamic> json) {return HorizontalPodAutoscalerSpec(scaleTargetRef: CrossVersionObjectReference.fromJson(json['scaleTargetRef']), minReplicas: json['minReplicas'], maxReplicas: json['maxReplicas'], metrics: json['metrics'] != null ? (json['metrics'] as List).map((e) => MetricSpec.fromJson(e)).toList() : null, behavior: json['behavior'] != null ? HPAScalingBehavior.fromJson(json['behavior']) : null);} Map<String, dynamic> toJson() {return {'scaleTargetRef' : scaleTargetRef.toJson(), 'minReplicas' : minReplicas, 'maxReplicas' : maxReplicas, if (metrics != null) 'metrics' : metrics!.map((e) => e.toJson()).toList(), if (behavior != null) 'behavior' : behavior!.toJson()};}}
